const models = $input.all()
  .map((item) => item.json)
  .sort((a, b) => (b.workerCount || 0) - (a.workerCount || 0));

if (models.length === 0) {
  throw new Error('No Sogni LLM models are available right now. Try again later.');
}

const artistName = String($('Ask For Artist Name').first().json.artistName || '').trim();
if (!artistName) {
  throw new Error('Artist name is required.');
}

const bestModel = models[0];

return {
  json: {
    artistName,
    modelId: bestModel.id,
    modelName: bestModel.label || bestModel.id,
    workerCount: bestModel.workerCount || 0,
    prompt: `Write a short witty rhyming poem about ${artistName}. Keep it to six lines or fewer, clever, warm, and email-friendly. Mention the artist by name.`,
    systemPrompt: 'You are a concise poet. Reply in plain text only with the poem. No title, no markdown, no preamble, no closing signature.',
    emailSubject: `Sogni LLM poem for ${artistName}`
  }
};

const poem = String($json.content || '').trim();

if (!poem) {
  throw new Error('The Sogni LLM response was empty.');
}

const escapeHtml = (value) => value
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;')
  .replace(/"/g, '&quot;')
  .replace(/'/g, '&#39;');

const modelId = String($json.modelId || 'unknown-model');
const artistName = String($json.artistName || 'this artist');
const poemHtml = escapeHtml(poem).replace(/\n/g, '<br>');

return {
  json: {
    ...$json,
    emailSubject: `Sogni LLM poem for ${artistName} (${modelId})`,
    emailHtml: `<p>Fresh from Sogni LLM for <strong>${escapeHtml(artistName)}</strong>:</p><p style="font-family: Georgia, serif; line-height: 1.6;">${poemHtml}</p><p><small>Model: ${escapeHtml(modelId)}</small></p>`
  }
};
